import React, { FunctionComponent, useState } from "react";
import { ctx } from "../services/Context";
import {Button, H1, Tab, Tabs} from "@blueprintjs/core";
import { observer } from "mobx-react";

export const Welcome: FunctionComponent = () => {
    // const test: string = ctx.store.menu;
    return (
        <div>
            {/*<Button onClick={() => ctx.menu.chooseMenu("none")} icon="undo">
                Return
            </Button>*/}
            <H1>Page d'accueil</H1>
            <Tabs id="TabsExample" onChange={this.handleTabChange} selectedTabId="rx">
                <Tab id="ng" title="Login" panel={<Login />} />
                <Tab id="mb" title="Register" panel={<Register />} panelClassName="ember-panel" />
                <Tab id="rx" title="React" panel={<ReactPanel />} />
                <Tab id="bb" disabled title="Backbone" panel={<BackbonePanel />} />
                <Tabs.Expander />
                <input className="bp3-input" type="text" placeholder="Search..." />
            </Tabs>
        </div>
    );
};
